import sys
import mysql.connector
from mysql.connector import Error

# Check if MySQL server local_infile is enabled
config = mysql.connector.connect(user='your_username', password='your_password')
cursor = config.cursor()
cursor.execute("SHOW VARIABLES LIKE 'local_infile'")
result = cursor.fetchone()
if result and result[1] == 'ON':
    pass  # local_infile is already enabled
else:
    print("Error: MySQL server local_infile is not enabled.")
    sys.exit(1)

config = mysql.connector.connect(user='your_username', password='your_password', local_infile=True)
cursor = config.cursor()

# Accept file paths from user input
file_path = input("Enter the file path: ")

try:
    cursor.execute("LOAD DATA INFILE '{}' INTO TABLE your_table_name FIELDS TERMINATED BY '\t'".format(file_path))
    config.commit()
    print("Data imported successfully.")
except Error as e:
    print(e)

cursor.close()
config.close()